fun solve(nums: Array<Long>): Array<Long> {
    val n = nums.size
    val ans = Array(2 * n) { 0L }

    // Copy the first half (0 to n-1)
    for (i in 0 until n) {
        ans[i] = nums[i]
    }

    // Copy the reversed second half (n to 2n-1)
    // ans[i + n] = nums[n - i - 1] for 0 <= i < n
    for (i in 0 until n) {
        val originalIndex = n - i - 1
        ans[i + n] = nums[originalIndex]
    }

    return ans
}

